"use strict";exports.formatDate=function(t,r="YYYY-MM-DD HH:mm:ss"){if(!t)return"";const e=new Date(t),a=e.getFullYear(),n=String(e.getMonth()+1).padStart(2,"0"),S=String(e.getDate()).padStart(2,"0"),i=String(e.getHours()).padStart(2,"0"),o=String(e.getMinutes()).padStart(2,"0"),p=String(e.getSeconds()).padStart(2,"0");return r.replace("YYYY",a).replace("MM",n).replace("DD",S).replace("HH",i).replace("mm",o).replace("ss",p)},exports.formatDistance=function(t){return t?t<1e3?`${t}m`:`${(t/1e3).toFixed(2)}km`:"0km"},exports.formatDuration=function(t){if(!t)return"00:00:00";const r=Math.floor(t/3600),e=Math.floor(t%3600/60),a=t%60;return r>0?`${String(r).padStart(2,"0")}:${String(e).padStart(2,"0")}:${String(a).padStart(2,"0")}`:`${String(e).padStart(2,"0")}:${String(a).padStart(2,"0")}`};
